import React, { useState } from "react";
import {
  DndContext,
  closestCenter,
  KeyboardSensor,
  PointerSensor,
  useSensor,
  useSensors,
} from "@dnd-kit/core";
import {
  arrayMove,
  SortableContext,
  sortableKeyboardCoordinates,
  verticalListSortingStrategy,
  useSortable,
} from "@dnd-kit/sortable";
import { CSS } from "@dnd-kit/utilities";
import { motion, AnimatePresence } from "framer-motion";
import { GripVertical, Pencil, Trash2, Plus, ToggleLeft, ToggleRight } from "lucide-react";
import { linkHomeDesign as design } from "../../design/linkHomeDesign"; // adjust path

const SortableItem = ({ link, handleEdit, handleDelete, handleToggleActive }) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: link.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.7 : 1,
    scale: isDragging ? 1.02 : 1,
  };

  return (
    <motion.div
      ref={setNodeRef}
      style={style}
      className={design.row}
      initial="hidden"
      animate="visible"
      exit="exit"
      variants={design.itemVariants}
      layout
    >
      <button
        className={design.dragHandle}
        {...attributes}
        {...listeners}
      >
        <GripVertical size={20} />
      </button>

      <div className={design.nameArea}>
        <span className={design.nameText}>{link.name}</span>
        <span className={design.urlText}>{link.url}</span>
      </div>

      <div className="flex items-center gap-6 lg:gap-8">
        <button
          onClick={() => handleToggleActive(link.id)}
          className="transition-transform hover:scale-110"
        >
          {link.active ? (
            <ToggleRight size={26} className="text-emerald-600" />
          ) : (
            <ToggleLeft size={26} className="text-slate-400" />
          )}
        </button>

        <div className={design.actions}>
          <button
            onClick={() => handleEdit(link)}
            className={design.actionBtn}
            title="Edit"
          >
            <Pencil size={18} />
          </button>
          <button
            onClick={() => handleDelete(link.id)}
            className={design.actionBtn}
            title="Delete"
          >
            <Trash2 size={18} className="text-red-500/80" />
          </button>
        </div>
      </div>
    </motion.div>
  );
};

const LinkHome = () => {
  const [links, setLinks] = useState([]);
  const [name, setName] = useState("");
  const [url, setUrl] = useState("");
  const [editingId, setEditingId] = useState(null);

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const handleDragEnd = (event) => {
    const { active, over } = event;
    if (active.id !== over.id) {
      setLinks((items) => {
        const oldIndex = items.findIndex((i) => i.id === active.id);
        const newIndex = items.findIndex((i) => i.id === over.id);
        return arrayMove(items, oldIndex, newIndex);
      });
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!name.trim() || !url.trim()) return;

    const trimmedUrl = url.trim().startsWith("http") ? url.trim() : `https://${url.trim()}`;

    if (editingId) {
      setLinks(
        links.map((l) =>
          l.id === editingId ? { ...l, name, url: trimmedUrl } : l
        )
      );
      setEditingId(null);
    } else {
      setLinks([...links, { id: Date.now(), name, url: trimmedUrl, active: true }]);
    }
    setName("");
    setUrl("");
  };

  const startEdit = (link) => {
    setName(link.name);
    setUrl(link.url);
    setEditingId(link.id);
  };

  const removeLink = (id) => {
    if (!window.confirm("Delete this navigation link?")) return;
    setLinks(links.filter((l) => l.id !== id));
  };

  const toggleActive = (id) => {
    setLinks(
      links.map((l) =>
        l.id === id ? { ...l, active: !l.active } : l
      )
    );
  };

  return (
    <div className={design.pageWrapper}>
      <div className={design.container}>
        {/* Header */}
        <div className={design.header}>
          <div>
            <h1 className={design.title}>Navigation Menu</h1>
            <p className={design.subtitle}>
              Reorder, edit and manage main navigation links for your public website. Drag items to change display order.
            </p>
          </div>
        </div>

        {/* Card */}
        <div className={design.card}>
          {/* Form */}
          <div className={design.formSection}>
            <form onSubmit={handleSubmit} className={design.form}>
              <div className={design.inputGroup}>
                <label className={design.label}>Link Label</label>
                <input
                  type="text"
                  placeholder="e.g. Features, Pricing, Blog"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className={design.inputBase}
                  autoFocus
                />
              </div>

              <div className={design.inputGroup}>
                <label className={design.label}>URL / Path</label>
                <input
                  type="text"
                  placeholder="e.g. /features or yoursite.com/blog"
                  value={url}
                  onChange={(e) => setUrl(e.target.value)}
                  className={design.inputBase}
                />
              </div>

              <motion.button
                whileTap={{ scale: 0.97 }}
                type="submit"
                className={design.buttonPrimary}
              >
                <Plus size={18} />
                {editingId ? "Update Link" : "Add New Link"}
              </motion.button>
            </form>
          </div>

          {/* Sortable List */}
          <DndContext
            sensors={sensors}
            collisionDetection={closestCenter}
            onDragEnd={handleDragEnd}
          >
            <SortableContext items={links} strategy={verticalListSortingStrategy}>
              <div className={design.listWrapper}>
                <AnimatePresence mode="popLayout">
                  {links.length === 0 ? (
                    <div className={design.empty}>
                      <p>No navigation links added yet.</p>
                      <p className="text-sm">Add your first link above to get started.</p>
                    </div>
                  ) : (
                    links.map((link) => (
                      <SortableItem
                        key={link.id}
                        link={link}
                        handleEdit={startEdit}
                        handleDelete={removeLink}
                        handleToggleActive={toggleActive}
                      />
                    ))
                  )}
                </AnimatePresence>
              </div>
            </SortableContext>
          </DndContext>
        </div>
      </div>
    </div>
  );
};

export default LinkHome;
